      "title": "Branching vs Chaining",
      "useCase": "Parallel vs sequential execution",
      "code": "const userPromise = fetch('/api/users/1').then(function(res) { return res.json(); });\n\n// BRANCHING: both run independently with the same data\nuserPromise.then(function(user) {\n  console.log('Email:', user.email);\n});\nuserPromise.then(function(user) {\n  console.log('Role:', user.role);\n});\n// Both console logs happen concurrently (or on same tick)\n\n// CHAINING: each step waits for the previous\nuserPromise\n  .then(function(user) {\n    return fetch('/api/orders?userId=' + user.id);\n  })\n  .then(function(res) { return res.json(); })\n  .then(function(orders) {\n    console.log('Orders:', orders);\n  });\n// Fetches orders AFTER user data is loaded",
