      "useCase": "Skip remaining steps on condition",
      "code": "function getDashboardData(userId) {\n  return fetch('/api/users/' + userId)\n    .then(function(res) { return res.json(); })\n    .then(function(user) {\n      // Early exit if user is not active\n      if (!user.active) {\n        return Promise.reject(new Error('User is inactive'));\n      }\n      return user;\n    })\n    .then(function(user) {\n      return fetch('/api/dashboard/' + user.id);\n    })\n    .then(function(res) { return res.json(); })\n    .then(function(data) {\n      renderDashboard(data);\n    })\n    .catch(function(err) {\n      showError(err.message);  // Handles both 'inactive' and network errors\n    });\n}\n\ngetDashboardData(42);",
