  "codeExamples": [
    {
      "title": "JSON.stringify Basic Usage",
      "useCase": "Converting objects to JSON strings",
      "code": "const user = {\n  name: 'Alice',\n  age: 30,\n  isAdmin: false,\n  roles: ['user', 'editor'],\n  address: null,\n  preferences: { theme: 'dark' },\n  login: undefined,     // omitted\n  greet: function() {},  // omitted\n  createdAt: new Date('2024-01-15')\n};\n\n// Basic serialization\nconst json = JSON.stringify(user);\nconsole.log(json);\n// {\"name\":\"Alice\",\"age\":30,\"isAdmin\":false,\"roles\":[\"user\",\"editor\"],\"address\":null,\"preferences\":{\"theme\":\"dark\"},\"createdAt\":\"2024-01-15T00:00:00.000Z\"}\n// Note: undefined and function are missing\n\n// Pretty-print (indentation)\nconsole.log(JSON.stringify(user, null, 2));\n// {\n//   \"name\": \"Alice\",\n//   \"age\": 30,\n//   ...\n// }",
      "description": "JSON.stringify converts JS objects to JSON strings. Functions, undefined, and symbols are stripped. Dates become ISO strings. Use the space parameter for readable output."
    },
    {
      "title": "JSON.parse Basic Usage",
      "useCase": "Converting JSON strings back to objects",
      "code": "const jsonString = '{\"name\":\"Alice\",\"age\":30,\"isAdmin\":false}';\n\n// Parse safely\ntry {\n  const user = JSON.parse(jsonString);\n  console.log(user.name);    // 'Alice'\n  console.log(user.age);     // 30\n  console.log(user.isAdmin); // false\n} catch (err) {\n  console.error('Invalid JSON:', err.message);\n}\n\n// Parsing with date revival (reviver function)\nconst dataWithDate = '{\"event\":\"Meeting\",\"date\":\"2024-01-15T10:00:00.000Z\"}';\nconst parsed = JSON.parse(dataWithDate, function(key, value) {\n  if (typeof value === 'string' && /^\\d{4}-\\d{2}-\\d{2}T/.test(value)) {\n    return new Date(value);\n  }\n  return value;\n});\n\nconsole.log(parsed.date instanceof Date); // true\nconsole.log(parsed.date.getFullYear());   // 2024",
      "description": "Always wrap JSON.parse in try/catch. The reviver function transforms values during parsing — useful for reviving dates, custom types, or filtering data."
    },
    {
      "title": "Using Replacer to Filter/Sanitize Output",
      "useCase": "Removing sensitive data before serialization",
      "code": "const user = {\n  id: 42,\n  name: 'Alice',\n  email: 'alice@example.com',\n  password: 'secret123',\n  ssn: '123-45-6789',\n  roles: ['admin']\n};\n\n// Replacer as an array — whitelist keys\nconst safe = JSON.stringify(user, ['id', 'name', 'email', 'roles']);\nconsole.log(safe);\n// {\"id\":42,\"name\":\"Alice\",\"email\":\"alice@example.com\",\"roles\":[\"admin\"]}\n\n// Replacer as a function — blacklist sensitive keys\nconst sanitized = JSON.stringify(user, function(key, value) {\n  if (['password', 'ssn', 'secret'].includes(key)) {\n    return undefined;  // Omit this key\n  }\n  return value;\n});\nconsole.log(sanitized);\n// {\"id\":42,\"name\":\"Alice\",\"email\":\"alice@example.com\",\"roles\":[\"admin\"]}\n\n// Replacer with transformation\nconst masked = JSON.stringify(user, function(key, value) {\n  if (key === 'ssn') return '***-**-****';\n  if (key === 'password') return undefined;\n  return value;\n}, 2);\nconsole.log(masked);\n// Shows masked SSN, no password",
      "description": "The replacer parameter controls what gets serialized. Use an array to whitelist specific keys or a function to transform/omit values dynamically."
    },
    {
      "title": "JSON deepClone using stringify/parse",
      "useCase": "Creating a deep copy of an object",
      "code": "function deepClone(obj) {\n  return JSON.parse(JSON.stringify(obj));\n}\n\nconst original = {\n  name: 'Original',\n  nested: { count: 1, items: ['a', 'b'] },\n  date: new Date('2024-01-15')\n};\n\nconst clone = deepClone(original);\n\n// Verify it's a true deep copy\nclone.name = 'Modified';\nclone.nested.count = 99;\nclone.nested.items.push('c');\n\nconsole.log(original.name);         // 'Original' (unchanged)\nconsole.log(original.nested.count);  // 1 (unchanged)\nconsole.log(original.nested.items);  // ['a', 'b'] (unchanged)\nconsole.log(clone.date instanceof Date); // false! (string, not Date)\n\n// Limitations:\n// - Functions, undefined, symbols are LOST\n// - Date becomes string (not revived)\n// - Circular references throw\n// - Map/Set become empty objects\n// For robust cloning, use structuredClone() or lodash.cloneDeep",
      "description": "JSON.parse(JSON.stringify(obj)) is a quick deep clone trick but has limitations. It only works for serializable data (no functions, dates, circular refs). For production, use structuredClone() or a library."
    },
    {
      "title": "Custom toJSON for Serialization Control",
      "useCase": "Controlling how objects are serialized",
      "code": "class Product {\n  constructor(id, name, price, discount) {\n    this.id = id;\n    this.name = name;\n    this.price = price;\n    this.discount = discount;  // 0-1\n  }\n\n  // Custom JSON serialization\n  toJSON() {\n    return {\n      productId: this.id,\n      displayName: this.name.toUpperCase(),\n      finalPrice: this.price * (1 - this.discount),\n      currency: 'USD'\n    };\n  }\n}\n\nconst product = new Product(1, 'Widget', 100, 0.2);\n\nconsole.log(JSON.stringify(product));\n// {\"productId\":1,\"displayName\":\"WIDGET\",\"finalPrice\":80,\"currency\":\"USD\"}\n\n// Without toJSON, it would serialize as:\n// {\"id\":1,\"name\":\"Widget\",\"price\":100,\"discount\":0.2}\n\n// toJSON also works inline:\nconst user = {\n  name: 'Alice',\n  password: 'secret',\n  toJSON() {\n    return { name: this.name };\n  }\n};\nconsole.log(JSON.stringify(user)); // {\"name\":\"Alice\"}",
      "description": "Objects with a toJSON() method control their own serialization. This is useful for transforming sensitive data, computing derived fields, or normalizing output formats."
    }
  ],
